import { useCallback, useEffect, useState } from 'react';
import { useTradeContext } from '../context/CedrosTradeProvider';
import { useReconnectingWebSocket } from '../utils/useReconnectingWebSocket';
import type { WsState } from '../utils/useReconnectingWebSocket';

export interface OrderbookLevel {
  price: number;
  size: number;
  total: number;
}

export interface OrderbookData {
  market: string;
  baseMint: string;
  quoteMint: string;
  bids: OrderbookLevel[];
  asks: OrderbookLevel[];
  spread: number;
  midPrice: number;
}

export interface UseOrderbookReturn {
  data: OrderbookData | null;
  isLoading: boolean;
  error: string | null;
  connectionState: WsState;
  retryCount: number;
}

export function useOrderbook(marketAddress: string | null, streaming = true): UseOrderbookReturn {
  const { config } = useTradeContext();
  const [data, setData] = useState<OrderbookData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const wsUrl = marketAddress && streaming
    ? config.serverUrl.replace(/^http/, 'ws') + `/ws/orderbook/${marketAddress}`
    : null;

  const onMessage = useCallback((raw: string) => {
    try { setData(JSON.parse(raw)); }
    catch { /* ignore parse errors */ }
  }, []);

  const { state: connectionState, retryCount } = useReconnectingWebSocket({
    url: wsUrl, onMessage, enabled: streaming,
  });

  // REST fallback when not streaming
  useEffect(() => {
    if (streaming || !marketAddress) return;
    setIsLoading(true);
    fetch(`${config.serverUrl}/orderbook/${marketAddress}`)
      .then(r => r.ok ? r.json() : Promise.reject('fetch failed'))
      .then(setData)
      .catch(e => setError(String(e)))
      .finally(() => setIsLoading(false));
  }, [marketAddress, streaming, config.serverUrl]);

  return { data, isLoading, error, connectionState, retryCount };
}
