import React, { useEffect, useState } from 'react';
import { useTradeApi } from '../../context/CedrosTradeProvider';
import type { TradeHistoryEntry } from '../../types';
import { LoadingSpinner } from '../shared/LoadingSpinner';

export interface TradeHistoryTableProps {
  walletAddress: string;
  mintFilter?: string;
  limit?: number;
  className?: string;
}

export function TradeHistoryTable({ walletAddress, mintFilter, limit = 50, className = '' }: TradeHistoryTableProps) {
  const api = useTradeApi();
  const [trades, setTrades] = useState<TradeHistoryEntry[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    api.getTradeHistory(walletAddress, mintFilter, limit)
      .then(data => setTrades(data.trades))
      .catch(e => setError(e.message))
      .finally(() => setIsLoading(false));
  }, [api, walletAddress, mintFilter, limit]);

  if (isLoading) return <div className="ct-flex ct-justify-center ct-py-8"><LoadingSpinner /></div>;
  if (error) return <div className="ct-text-center ct-py-4 ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Trade history unavailable — indexer not configured</div>;
  if (trades.length === 0) return <div className="ct-text-center ct-py-8 ct-text-sm ct-text-[hsl(var(--cedros-muted-foreground))]">No trade history</div>;

  return (
    <table className={`ct-w-full ct-text-sm ${className}`}>
      <thead>
        <tr className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))] ct-border-b ct-border-[hsl(var(--cedros-border))]">
          <th className="ct-text-left ct-py-2 ct-px-2">Date</th>
          <th className="ct-text-left ct-py-2">Type</th>
          <th className="ct-text-right ct-py-2">In</th>
          <th className="ct-text-right ct-py-2">Out</th>
          <th className="ct-text-right ct-py-2 ct-px-2">Source</th>
        </tr>
      </thead>
      <tbody>
        {trades.map((t, i) => (
          <tr key={`${t.signature}-${i}`} className="ct-border-b ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))]">
            <td className="ct-py-2 ct-px-2 ct-text-xs">{new Date(t.timestamp).toLocaleDateString()}</td>
            <td className="ct-py-2 ct-capitalize">{t.tradeType}</td>
            <td className="ct-py-2 ct-text-right ct-font-mono ct-text-xs">{t.inputAmount}</td>
            <td className="ct-py-2 ct-text-right ct-font-mono ct-text-xs">{t.outputAmount}</td>
            <td className="ct-py-2 ct-px-2 ct-text-right ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">{t.source}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}
