import { useCallback, useEffect, useRef, useState } from 'react';
import { useTradeApi } from '../context/CedrosTradeProvider';
import { useTradeContext } from '../context/CedrosTradeProvider';
import { useReconnectingWebSocket } from '../utils/useReconnectingWebSocket';
import type { PriceSnapshot } from '../types';
import type { WsState } from '../utils/useReconnectingWebSocket';

export interface UsePricesReturn {
  prices: Record<string, PriceSnapshot>;
  isLoading: boolean;
  error: string | null;
  getPrice: (mint: string) => Promise<PriceSnapshot>;
  subscribe: (mints: string[]) => void;
  unsubscribe: (mints: string[]) => void;
  connectionState: WsState;
}

export function usePrices(useWebSocket = true): UsePricesReturn {
  const api = useTradeApi();
  const { config } = useTradeContext();
  const [prices, setPrices] = useState<Record<string, PriceSnapshot>>({});
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const subscribedMints = useRef<Set<string>>(new Set());
  const pollRef = useRef<ReturnType<typeof setInterval>>();

  const wsUrl = useWebSocket
    ? config.serverUrl.replace(/^http/, 'ws') + '/ws/prices'
    : null;

  const onWsMessage = useCallback((raw: string) => {
    try {
      const msg = JSON.parse(raw);
      if (msg.type === 'price' && msg.mint) {
        setPrices(prev => ({ ...prev, [msg.mint]: msg }));
      }
    } catch { /* ignore */ }
  }, []);

  const { state: connectionState, send } = useReconnectingWebSocket({
    url: wsUrl, onMessage: onWsMessage, enabled: useWebSocket,
  });

  // Send subscribe message when WS connects or mints change
  const syncSubscriptions = useCallback(() => {
    const mints = Array.from(subscribedMints.current);
    if (mints.length > 0 && connectionState === 'connected') {
      send(JSON.stringify({ type: 'subscribe', mints }));
    }
  }, [connectionState, send]);

  useEffect(() => { syncSubscriptions(); }, [syncSubscriptions]);

  const subscribe = useCallback((mints: string[]) => {
    for (const m of mints) subscribedMints.current.add(m);
    if (connectionState === 'connected') {
      send(JSON.stringify({ type: 'subscribe', mints }));
    } else {
      // Fallback: fetch via REST
      api.getBatchPrices(mints).then(({ prices: snapshots }) => {
        setPrices(prev => {
          const next = { ...prev };
          for (const s of snapshots) next[s.mint] = s;
          return next;
        });
      }).catch(() => {});
    }
  }, [api, connectionState, send]);

  const unsubscribe = useCallback((mints: string[]) => {
    for (const m of mints) subscribedMints.current.delete(m);
    if (connectionState === 'connected') {
      send(JSON.stringify({ type: 'unsubscribe', mints }));
    }
  }, [connectionState, send]);

  // REST polling fallback when WS is not available
  useEffect(() => {
    if (useWebSocket && connectionState === 'connected') {
      clearInterval(pollRef.current);
      return;
    }
    const poll = async () => {
      const mints = Array.from(subscribedMints.current);
      if (mints.length === 0) return;
      try {
        const { prices: snapshots } = await api.getBatchPrices(mints);
        setPrices(prev => {
          const next = { ...prev };
          for (const s of snapshots) next[s.mint] = s;
          return next;
        });
      } catch { /* silent */ }
    };
    pollRef.current = setInterval(poll, 10_000);
    return () => clearInterval(pollRef.current);
  }, [api, useWebSocket, connectionState]);

  const getPrice = useCallback(async (mint: string) => {
    setIsLoading(true);
    try {
      const p = await api.getPrice(mint);
      setPrices(prev => ({ ...prev, [mint]: p }));
      return p;
    } catch (e: any) { setError(e.message); throw e; }
    finally { setIsLoading(false); }
  }, [api]);

  return { prices, isLoading, error, getPrice, subscribe, unsubscribe, connectionState };
}
