import { useCallback, useEffect, useState } from 'react';
import { useTradeApi } from '../context/CedrosTradeProvider';
import type { TokenRecord } from '../types';

export interface UseTokensReturn {
  tokens: TokenRecord[];
  isLoading: boolean;
  error: string | null;
  refresh: () => Promise<void>;
  getByMint: (mint: string) => TokenRecord | undefined;
  getBySymbol: (symbol: string) => TokenRecord | undefined;
}

export function useTokens(): UseTokensReturn {
  const api = useTradeApi();
  const [tokens, setTokens] = useState<TokenRecord[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const refresh = useCallback(async () => {
    setIsLoading(true); setError(null);
    try {
      const { tokens: list } = await api.getTokens();
      setTokens(list);
    } catch (e: any) { setError(e.message); }
    finally { setIsLoading(false); }
  }, [api]);

  useEffect(() => { refresh(); }, [refresh]);

  const getByMint = useCallback((mint: string) => tokens.find(t => t.mint === mint), [tokens]);
  const getBySymbol = useCallback((symbol: string) => {
    const upper = symbol.toUpperCase();
    return tokens.find(t => t.symbol.toUpperCase() === upper);
  }, [tokens]);

  return { tokens, isLoading, error, refresh, getByMint, getBySymbol };
}
