import React, { useState, useMemo, useCallback, useEffect } from 'react';
import type { TokenRecord } from '../../types';
import { useTokens } from '../../hooks/useTokens';

export interface TokenSelectorProps {
  isOpen: boolean;
  onClose: () => void;
  onSelect: (token: TokenRecord) => void;
  /** Mints to exclude from the list (e.g. the other side of the pair) */
  excludeMints?: string[];
  /** If set, only show these mints (allowlist) */
  allowedMints?: string[];
  className?: string;
}

export function TokenSelector({ isOpen, onClose, onSelect, excludeMints = [], allowedMints, className = '' }: TokenSelectorProps) {
  const { tokens } = useTokens();
  const [search, setSearch] = useState('');
  const [favorites, setFavorites] = useState<string[]>(() => {
    try { return JSON.parse(localStorage.getItem('ct-favorite-tokens') || '[]'); }
    catch { return []; }
  });

  const filtered = useMemo(() => {
    const q = search.toLowerCase();
    return tokens
      .filter(t => !excludeMints.includes(t.mint))
      .filter(t => !allowedMints || allowedMints.includes(t.mint))
      .filter(t => !q || t.symbol.toLowerCase().includes(q) || t.name.toLowerCase().includes(q) || t.mint.includes(q));
  }, [tokens, search, excludeMints, allowedMints]);

  const favoriteTokens = useMemo(() =>
    tokens.filter(t => favorites.includes(t.mint)),
  [tokens, favorites]);

  const toggleFavorite = useCallback((mint: string) => {
    setFavorites(prev => {
      const next = prev.includes(mint) ? prev.filter(m => m !== mint) : [...prev, mint];
      localStorage.setItem('ct-favorite-tokens', JSON.stringify(next));
      return next;
    });
  }, []);

  const handleSelect = useCallback((token: TokenRecord) => {
    onSelect(token);
    onClose();
    setSearch('');
  }, [onSelect, onClose]);

  useEffect(() => {
    if (isOpen) setSearch('');
  }, [isOpen]);

  if (!isOpen) return null;

  return (
    <div className={`ct-fixed ct-inset-0 ct-z-50 ct-flex ct-items-center ct-justify-center ct-bg-black/50 ${className}`} onClick={onClose}>
      <div className="ct-bg-[hsl(var(--cedros-background))] ct-border ct-border-[hsl(var(--cedros-border))] ct-rounded-cedros ct-w-full ct-max-w-md ct-max-h-[80vh] ct-flex ct-flex-col ct-shadow-xl" onClick={e => e.stopPropagation()}>
        {/* Header */}
        <div className="ct-flex ct-items-center ct-justify-between ct-px-4 ct-py-3 ct-border-b ct-border-[hsl(var(--cedros-border))]">
          <h3 className="ct-text-lg ct-font-semibold ct-text-[hsl(var(--cedros-foreground))]">Select Token</h3>
          <button onClick={onClose} className="ct-text-[hsl(var(--cedros-muted-foreground))] hover:ct-text-[hsl(var(--cedros-foreground))] ct-text-xl">&times;</button>
        </div>

        {/* Search */}
        <div className="ct-px-4 ct-py-3">
          <input
            type="text"
            placeholder="Search by name, symbol, or mint..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            className="ct-w-full ct-px-3 ct-py-2 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] ct-placeholder-[hsl(var(--cedros-muted-foreground))] ct-outline-none focus:ct-ring-2 focus:ct-ring-[hsl(var(--cedros-ring))]"
            autoFocus
          />
        </div>

        {/* Favorites */}
        {favoriteTokens.length > 0 && !search && (
          <div className="ct-px-4 ct-pb-2 ct-flex ct-flex-wrap ct-gap-2">
            {favoriteTokens.map(t => (
              <button key={t.mint} onClick={() => handleSelect(t)}
                className="ct-px-3 ct-py-1 ct-rounded-full ct-text-sm ct-bg-[hsl(var(--cedros-muted))] ct-text-[hsl(var(--cedros-foreground))] hover:ct-bg-[hsl(var(--cedros-primary))] hover:ct-text-[hsl(var(--cedros-primary-foreground))] ct-transition">
                {t.symbol}
              </button>
            ))}
          </div>
        )}

        {/* Token List */}
        <div className="ct-flex-1 ct-overflow-y-auto ct-px-2 ct-pb-2">
          {filtered.map(token => (
            <button key={token.mint} onClick={() => handleSelect(token)}
              className="ct-w-full ct-flex ct-items-center ct-gap-3 ct-px-3 ct-py-2 ct-rounded-cedros hover:ct-bg-[hsl(var(--cedros-muted))] ct-transition ct-text-left">
              {token.logoUrl && (
                <img src={token.logoUrl} alt={token.symbol} className="ct-w-8 ct-h-8 ct-rounded-full" />
              )}
              <div className="ct-flex-1 ct-min-w-0">
                <div className="ct-font-medium ct-text-[hsl(var(--cedros-foreground))]">{token.symbol}</div>
                <div className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))] ct-truncate">{token.name}</div>
              </div>
              <button onClick={e => { e.stopPropagation(); toggleFavorite(token.mint); }}
                className="ct-text-lg ct-text-[hsl(var(--cedros-muted-foreground))] hover:ct-text-yellow-400">
                {favorites.includes(token.mint) ? '★' : '☆'}
              </button>
            </button>
          ))}
          {filtered.length === 0 && (
            <div className="ct-text-center ct-py-8 ct-text-[hsl(var(--cedros-muted-foreground))]">No tokens found</div>
          )}
        </div>
      </div>
    </div>
  );
}
