import React, { useState } from 'react';

export interface AutoFeaturesState {
  priceTargets: { price: string; percentage: string }[];
  targetsEnabled: boolean;
  profitProtection: { enabled: boolean; dropPercent: string; activateAbove: string };
  stopLoss: { enabled: boolean; triggerPrice: string };
  trailingStop: { enabled: boolean; trailPercent: string };
}

export const defaultAutoFeatures: AutoFeaturesState = {
  priceTargets: [{ price: '', percentage: '' }],
  targetsEnabled: false,
  profitProtection: { enabled: false, dropPercent: '10', activateAbove: '' },
  stopLoss: { enabled: false, triggerPrice: '' },
  trailingStop: { enabled: false, trailPercent: '10' },
};

export interface AutoFeaturesProps {
  state: AutoFeaturesState;
  onChange: (state: AutoFeaturesState) => void;
  className?: string;
}

export function AutoFeatures({ state, onChange, className = '' }: AutoFeaturesProps) {
  const update = (partial: Partial<AutoFeaturesState>) => onChange({ ...state, ...partial });

  return (
    <div className={`ct-space-y-3 ${className}`}>
      {/* Price Targets */}
      <ToggleCard
        enabled={state.targetsEnabled}
        onToggle={v => update({ targetsEnabled: v })}
        icon="🎯" label="Price Targets"
        color="blue"
        description="Set multiple price targets to auto-sell portions"
      >
        <div className="ct-space-y-2">
          {state.priceTargets.map((t, i) => (
            <div key={i} className="ct-flex ct-items-center ct-gap-2">
              <input type="number" value={t.price} placeholder="Price"
                onChange={e => {
                  const targets = [...state.priceTargets];
                  targets[i] = { ...targets[i], price: e.target.value };
                  update({ priceTargets: targets });
                }}
                className="ct-flex-1 ct-px-2 ct-py-1.5 ct-text-sm ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-rounded ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
              <input type="number" value={t.percentage} placeholder="%"
                onChange={e => {
                  const targets = [...state.priceTargets];
                  targets[i] = { ...targets[i], percentage: e.target.value };
                  update({ priceTargets: targets });
                }}
                className="ct-w-20 ct-px-2 ct-py-1.5 ct-text-sm ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-rounded ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
              {state.priceTargets.length > 1 && (
                <button onClick={() => update({ priceTargets: state.priceTargets.filter((_, j) => j !== i) })}
                  className="ct-text-red-400 hover:ct-text-red-300 ct-text-sm">&times;</button>
              )}
            </div>
          ))}
          <button onClick={() => update({ priceTargets: [...state.priceTargets, { price: '', percentage: '' }] })}
            className="ct-text-xs ct-text-blue-400 hover:ct-text-blue-300">+ Add Target</button>
        </div>
      </ToggleCard>

      {/* Profit Protection (Trailing Stop from peak) */}
      <ToggleCard
        enabled={state.profitProtection.enabled}
        onToggle={v => update({ profitProtection: { ...state.profitProtection, enabled: v } })}
        icon="🛡️" label="Profit Protection"
        color="green"
        description="Auto-sell if price drops from peak"
      >
        <div className="ct-space-y-2">
          <div className="ct-flex ct-items-center ct-gap-2">
            <input type="number" value={state.profitProtection.dropPercent} placeholder="Drop %"
              onChange={e => update({ profitProtection: { ...state.profitProtection, dropPercent: e.target.value } })}
              className="ct-flex-1 ct-px-2 ct-py-1.5 ct-text-sm ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-rounded ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
            <span className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">% from peak</span>
          </div>
          <div className="ct-flex ct-items-center ct-gap-2">
            <input type="number" value={state.profitProtection.activateAbove} placeholder="Activate above"
              onChange={e => update({ profitProtection: { ...state.profitProtection, activateAbove: e.target.value } })}
              className="ct-flex-1 ct-px-2 ct-py-1.5 ct-text-sm ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-rounded ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
            <span className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">price</span>
          </div>
        </div>
      </ToggleCard>

      {/* Stop Loss */}
      <ToggleCard
        enabled={state.stopLoss.enabled}
        onToggle={v => update({ stopLoss: { ...state.stopLoss, enabled: v } })}
        icon="🛑" label="Stop Loss"
        color="red"
        description="Auto-sell if price drops below threshold"
      >
        <div className="ct-flex ct-items-center ct-gap-2">
          <input type="number" value={state.stopLoss.triggerPrice} placeholder="Stop price"
            onChange={e => update({ stopLoss: { ...state.stopLoss, triggerPrice: e.target.value } })}
            className="ct-flex-1 ct-px-2 ct-py-1.5 ct-text-sm ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-rounded ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
          <span className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">trigger</span>
        </div>
      </ToggleCard>

      {/* Trailing Stop */}
      <ToggleCard
        enabled={state.trailingStop.enabled}
        onToggle={v => update({ trailingStop: { ...state.trailingStop, enabled: v } })}
        icon="📉" label="Trailing Stop"
        color="orange"
        description="Stop-loss that follows price upward"
      >
        <div className="ct-flex ct-items-center ct-gap-2">
          <input type="number" value={state.trailingStop.trailPercent} placeholder="Trail %"
            onChange={e => update({ trailingStop: { ...state.trailingStop, trailPercent: e.target.value } })}
            className="ct-flex-1 ct-px-2 ct-py-1.5 ct-text-sm ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-rounded ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
          <span className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">% below peak</span>
        </div>
      </ToggleCard>
    </div>
  );
}

// --- Reusable toggle card ---

function ToggleCard({ enabled, onToggle, icon, label, color, description, children }: {
  enabled: boolean; onToggle: (v: boolean) => void;
  icon: string; label: string; color: string; description: string;
  children: React.ReactNode;
}) {
  const borderColor = enabled ? `ct-border-${color}-500/50` : 'ct-border-[hsl(var(--cedros-border))]';
  const bgColor = enabled ? `ct-bg-${color}-500/5` : '';

  return (
    <div className={`ct-border ct-rounded-cedros ct-p-3 ct-cursor-pointer ct-transition-all ${borderColor} ${bgColor}`}
      onClick={e => {
        if ((e.target as HTMLElement).closest('.ct-card-body')) return;
        onToggle(!enabled);
      }}>
      <div className="ct-flex ct-items-center ct-gap-2 ct-mb-1">
        <input type="checkbox" checked={enabled} onChange={e => { e.stopPropagation(); onToggle(e.target.checked); }}
          className="ct-w-4 ct-h-4 ct-rounded" />
        <span className="ct-text-base">{icon}</span>
        <span className="ct-text-sm ct-font-medium ct-text-[hsl(var(--cedros-foreground))]">{label}</span>
      </div>
      {enabled && (
        <div className="ct-card-body ct-mt-2 ct-space-y-2" onClick={e => e.stopPropagation()}>
          <p className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">{description}</p>
          {children}
        </div>
      )}
    </div>
  );
}
