import { useCallback, useState } from 'react';
import { useTradeApi } from '../context/CedrosTradeProvider';
import type { SwapQuote, SwapTransaction, ExecuteResult } from '../types';

export interface UseSwapReturn {
  quote: SwapQuote | null;
  transaction: SwapTransaction | null;
  result: ExecuteResult | null;
  isLoading: boolean;
  error: string | null;
  getQuote: (inputMint: string, outputMint: string, amount: string, slippageBps?: number) => Promise<SwapQuote>;
  buildTransaction: (quote: SwapQuote, userPublicKey: string) => Promise<SwapTransaction>;
  execute: (signedTransaction: string, provider: string, requestId?: string) => Promise<ExecuteResult>;
  compareProviders: (inputMint: string, outputMint: string, amount: string) => Promise<SwapQuote[]>;
  reset: () => void;
}

export function useSwap(): UseSwapReturn {
  const api = useTradeApi();
  const [quote, setQuote] = useState<SwapQuote | null>(null);
  const [transaction, setTransaction] = useState<SwapTransaction | null>(null);
  const [result, setResult] = useState<ExecuteResult | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const getQuote = useCallback(async (inputMint: string, outputMint: string, amount: string, slippageBps?: number) => {
    setIsLoading(true);
    setError(null);
    try {
      const q = await api.getQuote({ inputMint, outputMint, amount, slippageBps });
      setQuote(q);
      return q;
    } catch (e: any) {
      setError(e.message);
      throw e;
    } finally {
      setIsLoading(false);
    }
  }, [api]);

  const buildTransaction = useCallback(async (q: SwapQuote, userPublicKey: string) => {
    setIsLoading(true);
    setError(null);
    try {
      const tx = await api.buildSwap(q, userPublicKey);
      setTransaction(tx);
      return tx;
    } catch (e: any) {
      setError(e.message);
      throw e;
    } finally {
      setIsLoading(false);
    }
  }, [api]);

  const execute = useCallback(async (signedTransaction: string, provider: string, requestId?: string) => {
    setIsLoading(true);
    setError(null);
    try {
      const r = await api.executeSwap(signedTransaction, provider, requestId);
      setResult(r);
      return r;
    } catch (e: any) {
      setError(e.message);
      throw e;
    } finally {
      setIsLoading(false);
    }
  }, [api]);

  const compareProviders = useCallback(async (inputMint: string, outputMint: string, amount: string) => {
    setIsLoading(true);
    setError(null);
    try {
      return await api.compareQuotes(inputMint, outputMint, amount);
    } catch (e: any) {
      setError(e.message);
      throw e;
    } finally {
      setIsLoading(false);
    }
  }, [api]);

  const reset = useCallback(() => {
    setQuote(null);
    setTransaction(null);
    setResult(null);
    setError(null);
  }, []);

  return { quote, transaction, result, isLoading, error, getQuote, buildTransaction, execute, compareProviders, reset };
}
