import { useCallback, useEffect, useRef, useState } from 'react';

export type WsState = 'connecting' | 'connected' | 'disconnected' | 'reconnecting';

const INITIAL_BACKOFF = 1000;
const MAX_BACKOFF = 30000;
const MAX_RETRIES = 20;

export interface UseReconnectingWebSocketOptions {
  url: string | null;
  onMessage: (data: string) => void;
  enabled?: boolean;
}

export interface UseReconnectingWebSocketReturn {
  state: WsState;
  send: (data: string) => void;
  retryCount: number;
}

export function useReconnectingWebSocket({
  url, onMessage, enabled = true,
}: UseReconnectingWebSocketOptions): UseReconnectingWebSocketReturn {
  const [state, setState] = useState<WsState>('disconnected');
  const [retryCount, setRetryCount] = useState(0);
  const wsRef = useRef<WebSocket | null>(null);
  const backoffRef = useRef(INITIAL_BACKOFF);
  const retryTimerRef = useRef<ReturnType<typeof setTimeout>>();
  const mountedRef = useRef(true);
  const onMessageRef = useRef(onMessage);
  onMessageRef.current = onMessage;

  const connect = useCallback(() => {
    if (!url || !mountedRef.current) return;

    setState('connecting');
    const ws = new WebSocket(url);
    wsRef.current = ws;

    ws.onopen = () => {
      if (!mountedRef.current) { ws.close(); return; }
      setState('connected');
      backoffRef.current = INITIAL_BACKOFF;
      setRetryCount(0);
    };

    ws.onmessage = (event) => {
      onMessageRef.current(event.data);
    };

    ws.onclose = () => {
      if (!mountedRef.current) return;
      wsRef.current = null;
      scheduleReconnect();
    };

    ws.onerror = () => {
      // onclose will fire after onerror — reconnect handled there
    };
  }, [url]);

  const scheduleReconnect = useCallback(() => {
    if (!mountedRef.current) return;

    setRetryCount(prev => {
      if (prev >= MAX_RETRIES) {
        setState('disconnected');
        return prev;
      }
      setState('reconnecting');
      const delay = Math.min(backoffRef.current, MAX_BACKOFF);
      backoffRef.current = Math.min(delay * 2, MAX_BACKOFF);

      retryTimerRef.current = setTimeout(() => {
        if (mountedRef.current) connect();
      }, delay);

      return prev + 1;
    });
  }, [connect]);

  const send = useCallback((data: string) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(data);
    }
  }, []);

  useEffect(() => {
    mountedRef.current = true;
    if (enabled && url) connect();

    return () => {
      mountedRef.current = false;
      clearTimeout(retryTimerRef.current);
      wsRef.current?.close();
      wsRef.current = null;
    };
  }, [url, enabled, connect]);

  return { state, send, retryCount };
}
